import { WorkflowRuntime } from 'mastra/workflows';
import { trace } from '@vex_dev/sdk';

const detectWorkflowValidationGaps = (workflow: WorkflowRuntime) => {
  const transitions = workflow.getTransitions();
  return transitions.map(transition => {
    const inputSchema = transition.inputStep.outputSchema;
    const outputSchema = transition.outputStep.inputSchema;
    const hasValidation = transition.hasValidator();

    return {
      transitionId: transition.id,
      validated: hasValidation,
      schemaMismatch: !inputSchema.isCompatible(outputSchema),
      riskScore: hasValidation ? 0 : (inputSchema.isCompatible(outputSchema) ? 3 : 8)
    };
  }).filter(t => t.riskScore > 2);
};

import { AgentRuntime } from 'mastra/agents';
import { z } from 'zod';

const monitorToolCalls = async (agent: AgentRuntime) => {
  const issues: any[] = [];

  agent.onToolCall(async (call) => {
    try {
      const result = await call.execute();
      const expectedSchema = call.tool.schema;
      const validation = expectedSchema.safeParse(result);

      if (!validation.success) {
        issues.push({
          toolId: call.tool.id,
          malformed: true,
          errors: validation.error.errors,
          timestamp: new Date().toISOString()
        });
      }
    } catch (error) {
      issues.push({ toolId: call.tool.id, error: error.message });
    }
  });

  return issues;
};

import { KnowledgeRuntime } from 'mastra/knowledge';

const detectStaleMemory = (knowledge: KnowledgeRuntime) => {
  const recentCutoff = new Date(Date.now() - 24 * 60 * 60 * 1000);
  const retrievals = knowledge.getRecentRetrievals();

  return retrievals.map(retrieval => {
    const contextAge = new Date(retrieval.timestamp) - recentCutoff;
    const isStale = contextAge > 0;

    return {
      retrievalId: retrieval.id,
      contextAgeHours: contextAge / (1000 * 60 * 60),
      isStale,
      riskScore: isStale ? Math.min(contextAge / (1000 * 60 * 60), 10) : 0,
      usedInWorkflow: retrieval.workflowId
    };
  }).filter(r => r.riskScore > 2);
};

