import { WorkflowRuntime } from 'mastra/workflows';
import { VexMiddleware } from '@vex_dev/sdk';

const secureWorkflow = (workflow: WorkflowRuntime) => {
  const vex = new VexMiddleware({
    rules: ['validate_schema', 'prevent_hallucination', 'check_staleness']
  });

  workflow.useMiddleware(vex);

  workflow.onTransition(async (transition) => {
    const input = transition.inputData;
    const validation = await vex.validate(input, transition.outputSchema);

    if (!validation.valid) {
      throw new Error(`Validation failed: ${validation.errors.join(', ')}`);
    }

    return transition.proceed();
  });
};

import { AgentRuntime } from 'mastra/agents';
import { VexGuard } from '@vex_dev/sdk';

const secureAgentTools = (agent: AgentRuntime) => {
  const vexGuard = new VexGuard();

  agent.tools.forEach(tool => {
    const originalExecute = tool.execute;
    tool.execute = async (...args) => {
      const result = await originalExecute(...args);
      const validated = await vexGuard.validateToolResponse(
        tool.schema,
        result
      );

      if (!validated.valid) {
        console.warn('Tool response rejected:', validated.errors);
        return { error: 'Invalid tool response format' };
      }

      return validated.data;
    };
  });
};

import { KnowledgeRuntime } from 'mastra/knowledge';
import { VexContextFilter } from '@vex_dev/sdk';

const secureKnowledge = (knowledge: KnowledgeRuntime) => {
  const vexFilter = new VexContextFilter({
    maxAgeHours: 24,
    stalePenalty: 0.8
  });

  knowledge.setRetrievalFilter(async (query, contexts) => {
    const filtered = await vexFilter.filterContexts(contexts, {
      query,
      maxAge: 24 * 60 * 60 * 1000
    });

    return filtered.validContexts;
  });

  knowledge.onRetrieval(async (retrieval) => {
    const freshnessScore = await vexFilter.assessFreshness(retrieval.contexts);
    if (freshnessScore < 0.5) {
      console.warn('Stale context detected, score:', freshnessScore);
    }
  });
};

