import { MastraApp } from 'mastra/core';
import { Vex } from '@vex_dev/sdk';

const app = new MastraApp();

// Initialize Vex governance for entire Mastra app
const vex = new Vex({
  projectId: process.env.VEX_PROJECT_ID!,
  rules: {
    workflowValidation: 'strict',
    toolResponse: 'schema_enforced',
    memoryFreshness: '24h',
    integrationSync: 'atomic'
  }
});

// Auto-instrument all Mastra components
app.use(vex.middleware());

// Governance runs automatically on every:
// - workflow transition
// - agent tool call  
// - knowledge retrieval
// - integration sync

vex.onViolation(async (violation) => {
  console.error('Governance violation:', violation);
  // Auto-block unsafe actions
  violation.block();

  // Auto-generate fix PR
  await violation.createFixPR();
});

app.start();
